import requests, json, time, datetime
from datetime import timezone

# Phase 4: Register a QA member and trace flow
base = 'https://api.ivxholding.com'
ts = int(time.time())
email = f"qa-final-closeout-{ts}@proton.me"
password = "QACloseout2026!"

# Step 1: Register
reg_data = {
    'email': email,
    'password': password,
    'firstName': 'QA',
    'lastName': 'Closeout',
    'phone': '5551234567',
    'dateOfBirth': '1990-01-15',
    'gender': 'prefer_not_to_say'
}

reg_resp = requests.post(f'{base}/api/members/register', json=reg_data, timeout=20)
reg_json = reg_resp.json() if reg_resp.status_code < 500 else {}

# Step 2: Try login (should be blocked by verification gate)
login_data = {'email': email, 'password': password}
login_resp = requests.post(f'{base}/api/members/login', json=login_data, timeout=15)
login_json = login_resp.json() if login_resp.status_code < 500 else {}

# Step 3: Try wrong password (should 401)
wrong_login = requests.post(f'{base}/api/members/login', json={'email': email, 'password': 'wrongpass123'}, timeout=15)

# Step 4: Check member count
count_resp = requests.get(f'{base}/api/ivx/members/count', timeout=15)
count_json = count_resp.json() if count_resp.status_code == 200 else {}

auth_count_resp = requests.get(f'{base}/api/members/authoritative-count', timeout=15)
auth_count_json = auth_count_resp.json() if auth_count_resp.status_code == 200 else {}

# Step 5: Check if owner-action/list shows the new member (Admin HQ trace)
owner_action_resp = requests.get(f'{base}/api/ivx/owner-action/list', timeout=15)
owner_action_json = owner_action_resp.json() if owner_action_resp.status_code == 200 else {}

# Step 6: Try to access Admin HQ members endpoint (protected)
admin_members = requests.get(f'{base}/api/ivx/members', timeout=15)

result = {
    'timestamp': datetime.datetime.now(timezone.utc).isoformat(),
    'qa_email': email,
    'registration': {
        'status': reg_resp.status_code,
        'response': reg_json,
    },
    'login_with_correct_password': {
        'status': login_resp.status_code,
        'response': login_json,
        'blocked_by_verification': login_resp.status_code == 403,
    },
    'login_with_wrong_password': {
        'status': wrong_login.status_code,
        'rejected': wrong_login.status_code == 401,
    },
    'member_count': count_json,
    'authoritative_count': auth_count_json,
    'owner_action_list': {
        'status': owner_action_resp.status_code,
        'count': len(owner_action_json) if isinstance(owner_action_json, list) else 'N/A',
    },
    'admin_hq_members_access': {
        'status': admin_members.status_code,
        'blocked_unauthorized': admin_members.status_code == 401,
    },
}

print(json.dumps(result, indent=2))
with open('/home/user/rork-app/qa-evidence/member-flow-final.json', 'w') as f:
    json.dump(result, f, indent=2)
PYEOF
"}

