cd /home/user/rork-app
# Run Playwright reels interaction test
python3 << 'PYEOF'
import json, os, subprocess, time
from datetime import datetime, timezone

# Use Playwright to test reels interactions on the landing page
test_script = """
const { chromium } = require('playwright');

(async () => {
    const results = { timestamp: new Date().toISOString(), tests: [] };
    const browser = await chromium.launch({ headless: true });
    const context = await browser.newContext({
        viewport: { width: 390, height: 844 },
        userAgent: 'Mozilla/5.0 (iPhone; CPU iPhone OS 17_0 like Mac OS X) AppleWebKit/605.1.15',
        recordVideo: { dir: '/home/user/rork-app/qa-evidence/video-reels-final/', size: { width: 390, height: 844 } }
    });
    const page = await context.newPage();

    // Collect console errors
    const consoleErrors = [];
    page.on('console', msg => {
        if (msg.type() === 'error') consoleErrors.push(msg.text());
    });

    // Navigate to landing page
    await page.goto('https://ivxholding.com', { waitUntil: 'networkidle', timeout: 30000 });
    results.landingLoaded = true;

    // Wait for page to settle
    await page.waitForTimeout(2000);

    // Test 1: Open reels overlay
    try {
        const reelsBtn = await page.$('#ivxReelsBtn');
        if (reelsBtn) {
            await reelsBtn.click();
            await page.waitForTimeout(1500);
            const reelsOpen = await page.$('#ivxReels.open');
            results.tests.push({ name: 'open_reels', pass: !!reelsOpen, detail: 'Reels overlay opened' });
        } else {
            results.tests.push({ name: 'open_reels', pass: false, detail: 'Reels button not found' });
        }
    } catch(e) {
        results.tests.push({ name: 'open_reels', pass: false, detail: e.message });
    }

    // Test 2: Video is playing
    try {
        const videos = await page.$$('#ivxReels video');
        const activeVideo = videos[0];
        if (activeVideo) {
            const paused = await activeVideo.evaluate(el => el.paused);
            const currentTime = await activeVideo.evaluate(el => el.currentTime);
            results.tests.push({ name: 'video_playing', pass: !paused, detail: `paused=${paused}, currentTime=${currentTime}` });
        }
    } catch(e) {
        results.tests.push({ name: 'video_playing', pass: false, detail: e.message });
    }

    // Test 3: Mute toggle
    try {
        const muteBtn = await page.$('#ivxReels .reel-mute, #ivxReels .mute-btn, #ivxReels [class*="mute"]');
        if (muteBtn) {
            const mutedBefore = await page.$eval('#ivxReels video', el => el.muted);
            await muteBtn.click();
            await page.waitForTimeout(500);
            const mutedAfter = await page.$eval('#ivxReels video', el => el.muted);
            results.tests.push({ name: 'mute_toggle', pass: mutedBefore !== mutedAfter, detail: `muted: ${mutedBefore} -> ${mutedAfter}` });
        } else {
            // Try clicking the mute button by evaluating JS
            const mutedBefore = await page.$eval('#ivxReels video', el => el.muted);
            await page.evaluate(() => {
                const btn = document.querySelector('#ivxReels button[class*="mute"], #ivxReels .reel-mute');
                if (btn) btn.click();
            });
            await page.waitForTimeout(500);
            const mutedAfter = await page.$eval('#ivxReels video', el => el.muted);
            results.tests.push({ name: 'mute_toggle', pass: mutedBefore !== mutedAfter, detail: `muted: ${mutedBefore} -> ${mutedAfter} (via JS)` });
        }
    } catch(e) {
        results.tests.push({ name: 'mute_toggle', pass: false, detail: e.message });
    }

    // Test 4: Like button
    try {
        const likeBtn = await page.$('#ivxReels .reel-like, #ivxReels [class*="like"]');
        if (likeBtn) {
            const classBefore = await likeBtn.evaluate(el => el.className);
            await likeBtn.click();
            await page.waitForTimeout(500);
            const classAfter = await likeBtn.evaluate(el => el.className);
            results.tests.push({ name: 'like_toggle', pass: classBefore !== classAfter, detail: `class changed: ${classBefore !== classAfter}` });
        } else {
            results.tests.push({ name: 'like_toggle', pass: false, detail: 'Like button not found' });
        }
    } catch(e) {
        results.tests.push({ name: 'like_toggle', pass: false, detail: e.message });
    }

    // Test 5: Swipe to next slide
    try {
        const slidesBefore = await page.$$('#ivxReels .reel-slide, #ivxReels .slide');
        const countBefore = slidesBefore.length;

        // Simulate swipe up
        const reelsContainer = await page.$('#ivxReels .reels-container, #ivxReels .reels-scroll, #ivxReels');
        if (reelsContainer) {
            const box = await reelsContainer.boundingBox();
            if (box) {
                await page.mouse.move(box.x + box.width/2, box.y + box.height*0.7);
                await page.mouse.down();
                await page.mouse.move(box.x + box.width/2, box.y + box.height*0.3, { steps: 10 });
                await page.mouse.up();
                await page.waitForTimeout(1000);
            }
        }

        // Also try scroll
        await page.evaluate(() => {
            const container = document.querySelector('#ivxReels .reels-container, #ivxReels .reels-scroll, #ivxReels');
            if (container) container.scrollTop += 600;
        });
        await page.waitForTimeout(1500);

        const slidesAfter = await page.$$('#ivxReels .reel-slide, #ivxReels .slide');
        const countAfter = slidesAfter.length;
        results.tests.push({ name: 'swipe_next', pass: countAfter >= countBefore, detail: `slides: ${countBefore} -> ${countAfter}` });
    } catch(e) {
        results.tests.push({ name: 'swipe_next', pass: false, detail: e.message });
    }

    // Test 6: Count playing videos (one active player check)
