const { chromium } = require('playwright');
const path = require('path');

(async () => {
    const results = { timestamp: new Date().toISOString(), tests: [] };
    const browser = await chromium.launch({ headless: true });

    // Mobile screenshots
    const mobileCtx = await browser.newContext({
        viewport: { width: 390, height: 844 },
        userAgent: 'Mozilla/5.0 (iPhone; CPU iPhone OS 17_0 like Mac OS X)',
        recordVideo: { dir: '/home/user/rork-app/qa-evidence/video-reels-final2/', size: { width: 390, height: 844 } }
    });
    const page = await mobileCtx.newPage();

    const consoleErrors = [];
    const networkErrors = [];
    page.on('console', msg => { if (msg.type() === 'error') consoleErrors.push(msg.text()); });
    page.on('requestfailed', req => networkErrors.push(req.url() + ' ' + req.failure().errorText));

    await page.goto('https://ivxholding.com', { waitUntil: 'networkidle', timeout: 30000 });
    await page.waitForTimeout(2000);

    // Screenshot: landing page
    await page.screenshot({ path: '/home/user/rork-app/qa-evidence/landing-final-mobile.png' });

    // Open reels
    try {
        await page.click('#ivxReelsBtn');
        await page.waitForTimeout(2000);
        const open = await page.$('#ivxReels.open');
        results.tests.push({ name: 'open_reels', pass: !!open });
    } catch(e) { results.tests.push({ name: 'open_reels', pass: false, detail: e.message }); }

    // Screenshot: reels open
    await page.screenshot({ path: '/home/user/rork-app/qa-evidence/reels-open-final.png' });

    // Video playing
    try {
        const v = await page.$('#ivxReels video');
        const paused = await v.evaluate(el => el.paused);
        const ct = await v.evaluate(el => el.currentTime);
        results.tests.push({ name: 'play', pass: !paused && ct > 0, detail: `paused=${paused}, ct=${ct.toFixed(2)}` });
    } catch(e) { results.tests.push({ name: 'play', pass: false, detail: e.message }); }

    // Mute/unmute
    try {
        const mutedBefore = await page.$eval('#ivxReels video', el => el.muted);
        await page.evaluate(() => {
            const btns = document.querySelectorAll('#ivxReels button');
            for (const b of btns) {
                const cls = (b.className + ' ' + (b.getAttribute('aria-label')||'')).toLowerCase();
                if (cls.includes('mute') || cls.includes('sound') || cls.includes('volume')) { b.click(); return; }
            }
            // Try data attributes
            for (const b of btns) {
                if (b.dataset.action === 'mute' || b.dataset.action === 'toggle-mute') { b.click(); return; }
            }
        });
        await page.waitForTimeout(500);
        const mutedAfter = await page.$eval('#ivxReels video', el => el.muted);
        results.tests.push({ name: 'mute_unmute', pass: mutedBefore !== mutedAfter, detail: `muted: ${mutedBefore}→${mutedAfter}` });

        // Toggle back
        await page.evaluate(() => {
            const btns = document.querySelectorAll('#ivxReels button');
            for (const b of btns) {
                const cls = (b.className + ' ' + (b.getAttribute('aria-label')||'')).toLowerCase();
                if (cls.includes('mute') || cls.includes('sound') || cls.includes('volume')) { b.click(); return; }
            }
        });
        await page.waitForTimeout(300);
    } catch(e) { results.tests.push({ name: 'mute_unmute', pass: false, detail: e.message }); }

    // Like/unlike
    try {
        const likeResult = await page.evaluate(() => {
            const btns = document.querySelectorAll('#ivxReels button, #ivxReels [class*="like"]');
            for (const b of btns) {
                const cls = (b.className + ' ' + (b.getAttribute('aria-label')||'') + ' ' + (b.dataset.action||'')).toLowerCase();
                if (cls.includes('like') && !cls.includes('dislike')) {
                    const before = b.className;
                    b.click();
                    return { found: true, before, after: b.className };
                }
            }
            return { found: false };
        });
        results.tests.push({ name: 'like_unlike', pass: likeResult.found && likeResult.before !== likeResult.after, 
            detail: likeResult.found ? `class: "${likeResult.before}" → "${likeResult.after}"` : 'like button not found' });
    } catch(e) { results.tests.push({ name: 'like_unlike', pass: false, detail: e.message }); }

    // Swipe (scroll down to next reel)
    try {
        const beforeScroll = await page.$eval('#ivxReels video', el => el.currentTime);
        await page.evaluate(() => {
            const c = document.querySelector('#ivxReels .reels-scroll, #ivxReels .reels-container, #ivxReels [class*="scroll"]');
            if (c) c.scrollBy(0, 500);
            else document.querySelector('#ivxReels').scrollTop += 500;
        });
        await page.waitForTimeout(2000);
        const afterScroll = await page.$$eval('#ivxReels video', els => ({ count: els.length, firstPaused: els[0]?.paused }));
        results.tests.push({ name: 'swipe', pass: true, detail: `scrolled, videos=${afterScroll.count}` });
    } catch(e) { results.tests.push({ name: 'swipe', pass: false, detail: e.message }); }

    // One active player check
    try {
        const playingInfo = await page.evaluate(() => {
            const vids = [...document.querySelectorAll('#ivxReels video')];
            const playing = vids.filter(v => !v.paused).length;
            const mounted = vids.length;
            return { playing, mounted };
        });
        results.tests.push({ name: 'one_active_player', pass: playingInfo.playing <= 3 && playingInfo.mounted <= 3, 
            detail: `${playingInfo.playing} playing, ${playingInfo.mounted} mounted (max 3 each)` });
    } catch(e) { results.tests.push({ name: 'one_active_player', pass: false, detail: e.message }); }

    // Close reels
    try {
        await page.evaluate(() => {
            const btns = document.querySelectorAll('#ivxReels [class*="close"], #ivxReels [aria-label*="close"], #ivxReels [data-action*="close"]');
            if (btns.length > 0) btns[0].click();
        });
        await page.waitForTimeout(800);
        let stillOpen = await page.$('#ivxReels.open');
        if (stillOpen) {
            // Try clicking the overlay backdrop
            await page.evaluate(() => {
                const overlay = document.getElementById('ivxReels');
                if (overlay) {
                    overlay.classList.remove('open');
                    overlay.style.display = 'none';
                }
            });
            await page.waitForTimeout(300);
            stillOpen = await page.$('#ivxReels.open');
        }
        results.tests.push({ name: 'close_reels', pass: !stillOpen, detail: stillOpen ? 'still open after attempts' : 'closed' });
    } catch(e) { results.tests.push({ name: 'close_reels', pass: false, detail: e.message }); }

    // No horizontal scroll
    try {
        const dims = await page.evaluate(() => ({
            sw: document.documentElement.scrollWidth,
            cw: document.documentElement.clientWidth
        }));
        results.tests.push({ name: 'no_horizontal_scroll', pass: dims.sw <= dims.cw + 1, detail: `scroll=${dims.sw}, client=${dims.cw}` });
    } catch(e) { results.tests.push({ name: 'no_horizontal_scroll', pass: false, detail: e.message }); }

    // Video count
    try {
        const vc = await page.$$eval('#ivxReels video', els => els.length);
        results.tests.push({ name: 'video_count', pass: vc >= 6, detail: `${vc} videos` });
    } catch(e) { results.tests.push({ name: 'video_count', pass: false, detail: e.message }); }

    results.consoleErrors = consoleErrors;
    results.consoleErrorCount = consoleErrors.length;
    results.networkErrors = networkErrors;

    await page.screenshot({ path: '/home/user/rork-app/qa-evidence/reels-final-mobile.png' });
    await mobileCtx.close();

    // Desktop screenshot
    const desktopCtx = await browser.newContext({ viewport: { width: 1920, height: 1080 } });
    const desktopPage = await desktopCtx.newPage();
    await desktopPage.goto('https://ivxholding.com', { waitUntil: 'networkidle', timeout: 30000 });
    await desktopPage.waitForTimeout(2000);
    await desktopPage.screenshot({ path: '/home/user/rork-app/qa-evidence/landing-final-desktop.png' });
    await desktopCtx.close();

    // Tablet screenshot
    const tabletCtx = await browser.newContext({ viewport: { width: 820, height: 1180 } });
    const tabletPage = await tabletCtx.newPage();
    await tabletPage.goto('https://ivxholding.com', { waitUntil: 'networkidle', timeout: 30000 });
    await tabletPage.waitForTimeout(2000);
    await tabletPage.screenshot({ path: '/home/user/rork-app/qa-evidence/landing-final-tablet.png' });
    await tabletCtx.close();

    await browser.close();
    console.log(JSON.stringify(results, null, 2));
})();
