const { chromium } = require('playwright');

(async () => {
    const results = { timestamp: new Date().toISOString(), tests: [] };
    const browser = await chromium.launch({ headless: true });
    const context = await browser.newContext({
        viewport: { width: 390, height: 844 },
        userAgent: 'Mozilla/5.0 (iPhone; CPU iPhone OS 17_0 like Mac OS X)',
        recordVideo: { dir: '/home/user/rork-app/qa-evidence/video-reels-precise/', size: { width: 390, height: 844 } }
    });
    const page = await context.newPage();

    await page.goto('https://ivxholding.com', { waitUntil: 'networkidle', timeout: 30000 });
    await page.waitForTimeout(2000);

    // Open reels
    await page.click('#ivxReelsBtn');
    await page.waitForTimeout(2000);

    // Test: Like button (async — wait for response)
    try {
        const likeResult = await page.evaluate(async () => {
            const likeBtn = document.querySelector('#ivxReels .ivxr-act.like');
            if (!likeBtn) return { found: false };
            const classBefore = likeBtn.className;
            const iconBefore = likeBtn.querySelector('.i').innerHTML;

            // Click and wait for the async fetch to resolve
            likeBtn.click();

            // Wait up to 3 seconds for class change
            for (let i = 0; i < 30; i++) {
                await new Promise(r => setTimeout(r, 100));
                if (likeBtn.className !== classBefore) break;
            }

            return {
                found: true,
                classBefore,
                classAfter: likeBtn.className,
                iconBefore,
                iconAfter: likeBtn.querySelector('.i').innerHTML,
                countAfter: likeBtn.querySelector('.c').textContent
            };
        });
        results.tests.push({
            name: 'like_unlike',
            pass: likeResult.found && likeResult.classBefore !== likeResult.classAfter,
            detail: likeResult.found ? `class: "${likeResult.classBefore}" → "${likeResult.classAfter}", icon: ${likeResult.iconBefore} → ${likeResult.iconAfter}` : 'like button not found'
        });
    } catch(e) {
        results.tests.push({ name: 'like_unlike', pass: false, detail: e.message });
    }

    // Test: One active player (precise — count playing AND source-attached)
    try {
        const playerInfo = await page.evaluate(() => {
            const vids = [...document.querySelectorAll('#ivxReels video')];
            return vids.map(v => ({
                paused: v.paused,
                hasSrc: !!(v.src || v.querySelector('source') || v.__ivxAttached),
                preload: v.preload,
                readyState: v.readyState,
                currentSrc: v.currentSrc ? v.currentSrc.substring(0, 60) : 'none'
            }));
        });
        const playing = playerInfo.filter(v => !v.paused).length;
        const withSrc = playerInfo.filter(v => v.hasSrc || v.currentSrc !== 'none').length;
        const totalMounted = playerInfo.length;
        results.tests.push({
            name: 'one_active_player',
            pass: playing <= 1 && withSrc <= 3,
            detail: `playing=${playing}, withSrc=${withSrc}, mounted=${totalMounted} (threshold: 1 playing, max 3 with src)`
        });
        results.playerDetail = playerInfo;
    } catch(e) {
        results.tests.push({ name: 'one_active_player', pass: false, detail: e.message });
    }

    // Test: Comment button opens sheet
    try {
        await page.evaluate(() => {
            const cmtBtn = document.querySelector('#ivxReels .ivxr-act.cmt');
            if (cmtBtn) cmtBtn.click();
        });
        await page.waitForTimeout(1000);
        const sheetOpen = await page.$('#ivxReels .ivxr-sheet.open');
        results.tests.push({ name: 'comment_sheet', pass: !!sheetOpen, detail: sheetOpen ? 'Comment sheet opened' : 'Sheet not found' });

        // Close sheet
        await page.evaluate(() => {
            const closeBtn = document.querySelector('#ivxReels [data-r="sheetClose"]');
            if (closeBtn) closeBtn.click();
        });
        await page.waitForTimeout(500);
    } catch(e) {
        results.tests.push({ name: 'comment_sheet', pass: false, detail: e.message });
    }

    // Test: Share button (clipboard)
    try {
        const shareResult = await page.evaluate(async () => {
            const shrBtn = document.querySelector('#ivxReels .ivxr-act.shr');
            if (!shrBtn) return { found: false };
            shrBtn.click();
            await new Promise(r => setTimeout(r, 500));
            // Check if toast appeared
            const toast = document.querySelector('#ivxReels .ivxr-toast.on');
            return { found: true, toastText: toast ? toast.textContent : 'no toast' };
        });
        results.tests.push({ name: 'share', pass: shareResult.found, detail: shareResult.toastText || 'share clicked' });
    } catch(e) {
        results.tests.push({ name: 'share', pass: false, detail: e.message });
    }

    // Test: Save button
    try {
        const saveResult = await page.evaluate(async () => {
            const savBtn = document.querySelector('#ivxReels .ivxr-act.sav');
            if (!savBtn) return { found: false };
            const classBefore = savBtn.className;
            savBtn.click();
            await new Promise(r => setTimeout(r, 1500));
            return { found: true, classBefore, classAfter: savBtn.className };
        });
        results.tests.push({ name: 'save', pass: saveResult.found, detail: saveResult.found ? `class: ${saveResult.classBefore} → ${saveResult.classAfter}` : 'not found' });
    } catch(e) {
        results.tests.push({ name: 'save', pass: false, detail: e.message });
    }

    // Test: Pause (single tap on video area)
    try {
        const pausedResult = await page.evaluate(async () => {
            const slide = document.querySelector('#ivxReels .ivxr-slide');
            const vid = document.querySelector('#ivxReels video');
            if (!slide || !vid) return { found: false };
            const wasPaused = vid.paused;
            // Simulate single tap (not on rail/mute)
            slide.click();
            await new Promise(r => setTimeout(r, 500)); // wait for 330ms debounce
            return { found: true, wasPaused, isNowPaused: vid.paused };
        });
        results.tests.push({ name: 'pause_play', pass: pausedResult.found, detail: pausedResult.found ? `paused: ${pausedResult.wasPaused} → ${pausedResult.isNowPaused}` : 'not found' });
    } catch(e) {
        results.tests.push({ name: 'pause_play', pass: false, detail: e.message });
    }

    // Screenshot
    await page.screenshot({ path: '/home/user/rork-app/qa-evidence/reels-precise-final.png' });

    await browser.close();
    console.log(JSON.stringify(results, null, 2));
})();
